import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
import { Logger, withRetry } from "../_shared/logger.ts";
import { checkDeviceSubscription } from "../_shared/subscription-check.ts";
import { isValidPublicUrl } from "../_shared/url-utils.ts";
import { runPipeline, type PipelineContext } from "../_shared/pipeline-orchestrator.ts";
import { loadGenerationGlobals, applyVideoGlobals } from "../_shared/generation-globals.ts";
import { resolveTargetAspectRatio } from "../_shared/aspect-ratio.ts";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
};

interface GenerateVideoRequest {
  device_id: string;
  effect_id: string;
  input_image_url: string;
  secondary_image_url?: string;
  user_prompt?: string;
  detected_aspect_ratio?: string;
}

interface ProviderConfig {
  default_duration?: number;
  default_resolution?: string;
  default_aspect_ratio?: string;
  default_model_id?: string;
  poll_interval_seconds?: number;
  poll_timeout_minutes?: number;
}

interface GrokStartResponse {
  request_id?: string;
  error?: { message?: string };
}

async function loadProviderConfig(
  supabase: ReturnType<typeof createClient>,
  provider: string,
): Promise<ProviderConfig> {
  const { data } = await supabase
    .from("provider_config")
    .select("config")
    .eq("provider", provider)
    .maybeSingle();
  return (data?.config as ProviderConfig) ?? {};
}

serve(async (req) => {
  const logger = new Logger("generate-video");

  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    logger.info("request.received", { metadata: { method: req.method } });

    const supabaseUrl = Deno.env.get("SUPABASE_URL")!;
    const supabaseKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;
    const supabase = createClient(supabaseUrl, supabaseKey);
    const body: GenerateVideoRequest = await req.json();

    const { device_id, effect_id, input_image_url, secondary_image_url, user_prompt, detected_aspect_ratio } = body;

    logger.info("request.parsed", {
      metadata: { device_id, effect_id, has_prompt: !!user_prompt, has_secondary: !!secondary_image_url },
    });

    if (!device_id || !effect_id || !input_image_url) {
      logger.warn("validation.failed.missing_fields", {
        metadata: { device_id: !!device_id, effect_id: !!effect_id, input_image_url: !!input_image_url },
      });
      return new Response(
        JSON.stringify({ error: "Missing required fields: device_id, effect_id, input_image_url", request_id: logger.getRequestId() }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    if (!isValidPublicUrl(input_image_url)) {
      logger.warn("validation.invalid_primary_url", { metadata: { url_prefix: input_image_url.substring(0, 30) } });
      return new Response(
        JSON.stringify({ error: "input_image_url must be a publicly accessible HTTP(S) URL.", error_code: "INVALID_URL", request_id: logger.getRequestId() }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    if (secondary_image_url && !isValidPublicUrl(secondary_image_url)) {
      logger.warn("validation.invalid_secondary_url", { metadata: { url_prefix: secondary_image_url.substring(0, 30) } });
      return new Response(
        JSON.stringify({ error: "secondary_image_url must be a publicly accessible HTTP(S) URL.", error_code: "INVALID_URL", request_id: logger.getRequestId() }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const { data: effect, error: effectError } = await supabase
      .from("effects")
      .select("*")
      .eq("id", effect_id)
      .single();

    if (effectError || !effect) {
      logger.error("effect.fetch_failed", effectError || new Error(`Effect not found: ${effect_id}`));
      return new Response(
        JSON.stringify({ error: "Effect not found or invalid", error_code: "EFFECT_NOT_FOUND", request_id: logger.getRequestId() }),
        { status: 404, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    if (!effect.is_active) {
      logger.warn("effect.inactive", { metadata: { effect_id } });
      return new Response(
        JSON.stringify({ error: "This effect is no longer active", error_code: "EFFECT_INACTIVE", request_id: logger.getRequestId() }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    if (effect.requires_secondary_photo && !secondary_image_url) {
      logger.warn("validation.failed.missing_secondary", { metadata: { effect_id } });
      return new Response(
        JSON.stringify({ error: "This effect requires a secondary photo.", error_code: "MISSING_SECONDARY_PHOTO", request_id: logger.getRequestId() }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    let finalPrompt = effect.system_prompt_template;
    if (finalPrompt.includes("{{user_prompt}}")) {
      if (user_prompt && user_prompt.trim().length > 0) {
        finalPrompt = finalPrompt.replace("{{user_prompt}}", user_prompt.trim());
      } else {
        finalPrompt = finalPrompt.replace("{{user_prompt}}", "").trim();
      }
    }

    let { data: device } = await supabase.from("devices").select("id").eq("device_id", device_id).single();

    if (!device) {
      logger.info("device.creating", { metadata: { device_id } });
      const { data: newDevice, error: insertError } = await supabase
        .from("devices")
        .insert({ device_id })
        .select("id")
        .single();

      if (insertError) {
        logger.error("device.create_failed", insertError);
        return new Response(
          JSON.stringify({ error: "Failed to create device record", request_id: logger.getRequestId(), details: insertError }),
          { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }
      device = newDevice;
      logger.info("device.created", { metadata: { device_uuid: device.id } });
    }

    const subscriptionCheck = await checkDeviceSubscription(supabase, device.id, device_id);

    if (!subscriptionCheck.valid) {
      logger.warn("subscription.invalid", {
        metadata: { error_code: subscriptionCheck.errorCode, error: subscriptionCheck.error, device_id },
      });
      const statusCode = subscriptionCheck.errorCode === "LIMIT_REACHED" ? 429 : 403;
      return new Response(
        JSON.stringify({
          error: subscriptionCheck.error,
          error_code: subscriptionCheck.errorCode,
          limit: subscriptionCheck.generationLimit,
          period_days: subscriptionCheck.periodDays,
          used: subscriptionCheck.generationsUsed,
          remaining: subscriptionCheck.generationsRemaining,
          request_id: logger.getRequestId(),
        }),
        { status: statusCode, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const { data: generation, error: genError } = await supabase
      .from("generations")
      .insert({
        device_id: device.id,
        effect_id: effect_id,
        input_image_url: input_image_url,
        secondary_image_url: secondary_image_url || null,
        reference_video_url: null,
        prompt: finalPrompt,
        status: "pending",
        provider: "grok",
        request_id: logger.getRequestId(),
        input_payload: { user_prompt: user_prompt ?? null },
        error_log: [],
      })
      .select()
      .single();

    if (genError) {
      logger.error("generation.create_failed", genError);
      return new Response(
        JSON.stringify({ error: "Failed to create generation record", request_id: logger.getRequestId(), details: genError }),
        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    logger.setGenerationId(generation.id);
    logger.info("generation.created", { metadata: { generation_id: generation.id } });

    // --- Pipeline routing: check if this effect has an active pipeline ---
    const preGlobals = await loadGenerationGlobals(supabase, logger);

    const { data: effectPipeline } = await supabase
      .from("effect_pipelines")
      .select("pipeline_id, config_overrides, pipeline_templates!inner(id, is_active)")
      .eq("effect_id", effect_id)
      .eq("is_active", true)
      .limit(1)
      .maybeSingle();

    if (effectPipeline?.pipeline_id && preGlobals.pipelines_enabled !== false) {
      logger.info("pipeline.routing", { metadata: { pipeline_id: effectPipeline.pipeline_id } });

      try {
        const targetAspectRatio = resolveTargetAspectRatio({
          detectedAspectRatio: detected_aspect_ratio,
          effectDefaultAspectRatio: (effect.generation_params as Record<string, unknown>)?.aspect_ratio as string | undefined,
        });

        const pipelineContext: PipelineContext = {
          user_image: input_image_url,
          user_prompt: user_prompt || "",
          effect_id,
          effect_name: effect.name,
          effect_concept: effect.system_prompt_template,
          effect_concept_resolved: finalPrompt,
          target_aspect_ratio: targetAspectRatio,
          ...(secondary_image_url ? { secondary_image: secondary_image_url } : {}),
        };

        const pipelineResult = await runPipeline(
          effectPipeline.pipeline_id,
          generation.id,
          pipelineContext,
          supabase,
          logger,
        );

        if (pipelineResult.providerRequestId) {
          await supabase
            .from("generations")
            .update({
              status: "processing",
              prompt: pipelineResult.finalPrompt || finalPrompt,
              provider_request_id: pipelineResult.providerRequestId,
              pipeline_execution_id: pipelineResult.pipelineExecutionId,
              api_response: {
                provider: "grok",
                request_id: pipelineResult.providerRequestId,
                pipeline_execution_id: pipelineResult.pipelineExecutionId,
              },
              error_log: logger.getLogs(),
            })
            .eq("id", generation.id);

          return new Response(
            JSON.stringify({
              success: true,
              generation_id: generation.id,
              status: "processing",
              pipeline_execution_id: pipelineResult.pipelineExecutionId,
              api_response: { provider: "grok", request_id: pipelineResult.providerRequestId },
              request_id: logger.getRequestId(),
            }),
            { headers: { ...corsHeaders, "Content-Type": "application/json" } }
          );
        } else {
          await supabase
            .from("generations")
            .update({ status: "completed", error_log: logger.getLogs() })
            .eq("id", generation.id);

          return new Response(
            JSON.stringify({
              success: true,
              generation_id: generation.id,
              status: "completed",
              pipeline_execution_id: pipelineResult.pipelineExecutionId,
              request_id: logger.getRequestId(),
            }),
            { headers: { ...corsHeaders, "Content-Type": "application/json" } }
          );
        }
      } catch (pipelineError) {
        const errMsg = pipelineError instanceof Error ? pipelineError.message : String(pipelineError);
        logger.error("pipeline.failed", pipelineError instanceof Error ? pipelineError : new Error(errMsg));

        await supabase
          .from("generations")
          .update({
            status: "failed",
            error_message: `Pipeline failed: ${errMsg}`,
            error_log: logger.getLogs(),
          })
          .eq("id", generation.id);

        await supabase.from("failed_generations").insert({
          original_generation_id: generation.id,
          device_id: device.id,
          failure_reason: "pipeline_execution_failed",
          final_error_message: errMsg,
          error_log: logger.getLogs(),
          retry_count: 0,
        });

        return new Response(
          JSON.stringify({
            success: false,
            generation_id: generation.id,
            status: "failed",
            error: errMsg,
            request_id: logger.getRequestId(),
          }),
          { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }
    }

    // --- Direct-to-Grok flow (no pipeline) ---
    const grokApiKey = Deno.env.get("GROK_API_KEY");
    if (!grokApiKey) {
      logger.error("config.missing", "GROK_API_KEY not configured");
      await supabase
        .from("generations")
        .update({
          status: "failed",
          error_message: "GROK_API_KEY not configured",
          error_log: logger.getLogs(),
        })
        .eq("id", generation.id);
      return new Response(
        JSON.stringify({ error: "Configuration Error: GROK_API_KEY missing", request_id: logger.getRequestId() }),
        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const providerCfg = await loadProviderConfig(supabase, "grok");
    const effectParams = (effect.generation_params || {}) as Record<string, unknown>;
    const globals = await loadGenerationGlobals(supabase, logger);

    const rawDuration = (effectParams.duration as number) ?? providerCfg.default_duration ?? 10;
    const rawResolution = (effectParams.resolution as string) ?? providerCfg.default_resolution ?? "720p";
    const rawAspectRatio = (effectParams.aspect_ratio as string) ?? providerCfg.default_aspect_ratio ?? "9:16";
    const rawModel = effect.ai_model_id || (effectParams.model_id as string) || providerCfg.default_model_id || "grok-imagine-video";

    const videoParams = applyVideoGlobals(globals, {
      duration: rawDuration,
      resolution: rawResolution,
      aspectRatio: rawAspectRatio,
      model: rawModel,
    });

    const grokBody: Record<string, unknown> = {
      model: videoParams.model,
      prompt: finalPrompt,
      image: { url: input_image_url },
      duration: videoParams.duration,
      aspect_ratio: videoParams.aspectRatio,
      resolution: videoParams.resolution,
    };

    logger.info("grok.calling", { metadata: { duration: videoParams.duration, resolution: videoParams.resolution, aspect_ratio: videoParams.aspectRatio, globals_applied: true } });

    const grokCall = async (): Promise<GrokStartResponse> => {
      const res = await fetch("https://api.x.ai/v1/videos/generations", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${grokApiKey}`,
        },
        body: JSON.stringify(grokBody),
      });
      if (!res.ok) {
        const errText = await res.text();
        throw new Error(`Grok API ${res.status}: ${errText}`);
      }
      return res.json();
    };

    const retryResult = await withRetry(grokCall, logger, { maxRetries: 1 });

    if ("error" in retryResult) {
      logger.error("grok.failed_permanently", retryResult.error);
      await supabase
        .from("generations")
        .update({
          status: "failed",
          error_message: retryResult.error.message,
          retry_count: retryResult.attempts,
          last_error_at: new Date().toISOString(),
          error_log: logger.getLogs(),
        })
        .eq("id", generation.id);

      await supabase.from("failed_generations").insert({
        original_generation_id: generation.id,
        device_id: device.id,
        failure_reason: "grok_api_call_failed",
        final_error_message: retryResult.error.message,
        error_log: logger.getLogs(),
        retry_count: retryResult.attempts,
      });

      return new Response(
        JSON.stringify({ success: false, generation_id: generation.id, status: "failed", error: retryResult.error.message, request_id: logger.getRequestId() }),
        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const grokResult = retryResult.result;
    logger.info("grok.response_received", { api_response: grokResult });

    if (!grokResult.request_id) {
      const errMsg = grokResult.error?.message || "Grok did not return a request_id";
      logger.error("grok.no_request_id", errMsg);
      await supabase
        .from("generations")
        .update({
          status: "failed",
          error_message: errMsg,
          api_response: grokResult,
          error_log: logger.getLogs(),
        })
        .eq("id", generation.id);

      return new Response(
        JSON.stringify({ success: false, generation_id: generation.id, status: "failed", error: errMsg, request_id: logger.getRequestId() }),
        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    await supabase
      .from("generations")
      .update({
        status: "processing",
        provider_request_id: grokResult.request_id,
        api_response: { provider: "grok", request_id: grokResult.request_id },
        retry_count: retryResult.attempts,
        error_log: logger.getLogs(),
      })
      .eq("id", generation.id);

    logger.info("grok.generation_queued", { metadata: { grok_request_id: grokResult.request_id } });

    return new Response(
      JSON.stringify({
        success: true,
        generation_id: generation.id,
        status: "processing",
        api_response: { provider: "grok", request_id: grokResult.request_id },
        request_id: logger.getRequestId(),
      }),
      { headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  } catch (error) {
    logger.error("request.unhandled_error", error instanceof Error ? error : new Error(String(error)));
    const errorMessage = error instanceof Error ? error.message : "Unknown error";
    return new Response(
      JSON.stringify({ error: errorMessage, request_id: logger.getRequestId(), details: error }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});

/**
 * Aspect ratio detection and resolution utilities.
 *
 * Maps arbitrary image dimensions to the set of standard ratios supported by
 * both Gemini image editing and Grok video generation, and resolves the final
 * target aspect ratio for a pipeline run using the priority chain:
 *   effect.forced_aspect_ratio → client detected → effect default → provider default → "9:16"
 */

export const SUPPORTED_ASPECT_RATIOS = [
  "9:16",
  "1:1",
  "16:9",
] as const;

export type SupportedAspectRatio = (typeof SUPPORTED_ASPECT_RATIOS)[number];

const RATIO_VALUES: Record<SupportedAspectRatio, number> = {
  "9:16": 9 / 16,   // 0.5625
  "1:1": 1,
  "16:9": 16 / 9,   // 1.778
};

/**
 * Classify a width/height ratio to the nearest supported standard.
 * Boundaries are geometric midpoints between adjacent ratios.
 */
export function classifyAspectRatio(widthOverHeight: number): SupportedAspectRatio {
  if (widthOverHeight < 0.78) return "9:16";
  if (widthOverHeight < 1.39) return "1:1";
  return "16:9";
}

function isSupported(value: string): value is SupportedAspectRatio {
  return (SUPPORTED_ASPECT_RATIOS as readonly string[]).includes(value);
}

/**
 * Parse an aspect ratio string like "9:16" into a numeric w/h value.
 */
export function parseAspectRatio(ratio: string): number | null {
  const parts = ratio.split(":");
  if (parts.length !== 2) return null;
  const w = parseFloat(parts[0]);
  const h = parseFloat(parts[1]);
  if (!w || !h) return null;
  return w / h;
}

/**
 * Get the numeric w/h value for a supported aspect ratio string.
 */
export function aspectRatioValue(ratio: SupportedAspectRatio): number {
  return RATIO_VALUES[ratio];
}

export interface AspectRatioResolutionInput {
  /** Admin-configured forced ratio on the effect (overrides everything) */
  effectForcedAspectRatio?: string;
  /** Client-detected ratio sent from iOS */
  detectedAspectRatio?: string;
  /** Default ratio from effect.generation_params.aspect_ratio */
  effectDefaultAspectRatio?: string;
  /** Default from provider_config */
  providerDefaultAspectRatio?: string;
}

/**
 * Resolve the target aspect ratio for a generation run.
 *
 * Priority: forced → detected → effect default → provider default → "9:16"
 *
 * Any value that isn't in SUPPORTED_ASPECT_RATIOS is ignored so that an
 * invalid client value can never break the pipeline.
 */
export function resolveTargetAspectRatio(
  input: AspectRatioResolutionInput,
): SupportedAspectRatio {
  const candidates = [
    input.effectForcedAspectRatio,
    input.detectedAspectRatio,
    input.effectDefaultAspectRatio,
    input.providerDefaultAspectRatio,
  ];

  for (const candidate of candidates) {
    if (candidate && isSupported(candidate)) {
      return candidate;
    }
  }

  return "9:16";
}

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
import { Logger } from "./logger.ts";

export interface GenerationGlobals {
  video_resolution: string | null;
  video_max_duration: number | null;
  video_aspect_ratio: string | null;
  image_enhance_enabled: boolean;
  image_analyze_enabled: boolean;
  prompt_enrich_enabled: boolean;
  image_enhance_model: string | null;
  image_analyze_model: string | null;
  prompt_enrich_model: string | null;
  video_generate_model: string | null;
  pipelines_enabled: boolean;
}

const DEFAULTS: GenerationGlobals = {
  video_resolution: null,
  video_max_duration: null,
  video_aspect_ratio: null,
  image_enhance_enabled: true,
  image_analyze_enabled: true,
  prompt_enrich_enabled: true,
  image_enhance_model: null,
  image_analyze_model: null,
  prompt_enrich_model: null,
  video_generate_model: null,
  pipelines_enabled: true,
};

let cached: GenerationGlobals | null = null;
let cachedAt = 0;
const CACHE_TTL_MS = 30_000;

export async function loadGenerationGlobals(
  supabase: ReturnType<typeof createClient>,
  logger: Logger,
): Promise<GenerationGlobals> {
  if (cached && Date.now() - cachedAt < CACHE_TTL_MS) {
    return cached;
  }

  try {
    const { data, error } = await supabase
      .from("system_config")
      .select("value")
      .eq("key", "generation_globals")
      .maybeSingle();

    if (error || !data) {
      logger.warn("generation_globals.load_failed", { metadata: { error: error?.message } });
      cached = { ...DEFAULTS };
    } else {
      cached = { ...DEFAULTS, ...(data.value as Partial<GenerationGlobals>) };
    }
  } catch (e) {
    logger.warn("generation_globals.exception", { metadata: { error: String(e) } });
    cached = { ...DEFAULTS };
  }

  cachedAt = Date.now();
  logger.info("generation_globals.loaded", { metadata: { globals: cached } });
  return cached;
}

export function applyVideoGlobals(
  globals: GenerationGlobals,
  params: { duration?: number; resolution?: string; aspectRatio?: string; model?: string },
): { duration: number; resolution: string; aspectRatio: string; model: string } {
  let duration = params.duration || 10;
  if (globals.video_max_duration != null && duration > globals.video_max_duration) {
    duration = globals.video_max_duration;
  }

  const resolution = globals.video_resolution || params.resolution || "720p";
  const aspectRatio = globals.video_aspect_ratio || params.aspectRatio || "9:16";
  const model = globals.video_generate_model || params.model || "grok-imagine-video";

  return { duration, resolution, aspectRatio, model };
}

export function isStepEnabled(globals: GenerationGlobals, stepType: string): boolean {
  switch (stepType) {
    case "image_enhance":
      return globals.image_enhance_enabled !== false;
    case "image_analyze":
      return globals.image_analyze_enabled !== false;
    case "prompt_enrich":
      return globals.prompt_enrich_enabled !== false;
    default:
      return true;
  }
}

export function getModelOverride(globals: GenerationGlobals, stepType: string): string | null {
  switch (stepType) {
    case "image_enhance":
      return globals.image_enhance_model || null;
    case "image_analyze":
      return globals.image_analyze_model || null;
    case "prompt_enrich":
      return globals.prompt_enrich_model || null;
    case "video_generate":
      return globals.video_generate_model || null;
    default:
      return null;
  }
}

// Structured logging utility for edge functions

export type LogLevel = 'debug' | 'info' | 'warn' | 'error';

export interface LogEntry {
  timestamp: string;
  level: LogLevel;
  event: string;
  request_id?: string;
  generation_id?: string;
  message?: string;
  duration_ms?: number;
  retry_attempt?: number;
  api_response?: unknown;
  error?: {
    message: string;
    code?: string;
    stack?: string;
  };
  metadata?: Record<string, unknown>;
}

export interface LogContext {
  request_id: string;
  generation_id?: string;
  function_name: string;
}

/**
 * Generate a unique request ID for correlation
 */
export function generateRequestId(): string {
  return `req_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;
}

/**
 * Create a structured log entry
 */
export function createLogEntry(
  level: LogLevel,
  event: string,
  context: Partial<LogContext>,
  details?: Partial<Omit<LogEntry, 'timestamp' | 'level' | 'event'>>
): LogEntry {
  return {
    timestamp: new Date().toISOString(),
    level,
    event,
    request_id: context.request_id,
    generation_id: context.generation_id,
    ...details,
  };
}

/**
 * Logger class for consistent structured logging
 */
export class Logger {
  private context: LogContext;
  private logs: LogEntry[] = [];

  constructor(functionName: string, requestId?: string) {
    this.context = {
      function_name: functionName,
      request_id: requestId || generateRequestId(),
    };
  }

  setGenerationId(id: string) {
    this.context.generation_id = id;
  }

  getRequestId(): string {
    return this.context.request_id;
  }

  getLogs(): LogEntry[] {
    return this.logs;
  }

  private log(level: LogLevel, event: string, details?: Partial<Omit<LogEntry, 'timestamp' | 'level' | 'event'>>) {
    const entry = createLogEntry(level, event, this.context, details);
    this.logs.push(entry);

    // Also output to console for Supabase logs
    const logMethod = level === 'error' ? console.error : 
                      level === 'warn' ? console.warn : 
                      level === 'debug' ? console.debug : console.info;

    logMethod(JSON.stringify(entry));
    return entry;
  }

  debug(event: string, details?: Partial<Omit<LogEntry, 'timestamp' | 'level' | 'event'>>) {
    return this.log('debug', event, details);
  }

  info(event: string, details?: Partial<Omit<LogEntry, 'timestamp' | 'level' | 'event'>>) {
    return this.log('info', event, details);
  }

  warn(event: string, details?: Partial<Omit<LogEntry, 'timestamp' | 'level' | 'event'>>) {
    return this.log('warn', event, details);
  }

  error(event: string, error: Error | string, details?: Partial<Omit<LogEntry, 'timestamp' | 'level' | 'event'>>) {
    const errorObj = error instanceof Error 
      ? { message: error.message, stack: error.stack }
      : { message: error };

    return this.log('error', event, { ...details, error: errorObj });
  }
}

/**
 * Retry with exponential backoff
 */
export interface RetryConfig {
  maxRetries: number;
  initialDelayMs: number;
  maxDelayMs: number;
  backoffMultiplier: number;
}

export const DEFAULT_RETRY_CONFIG: RetryConfig = {
  maxRetries: 3,
  initialDelayMs: 5000,
  maxDelayMs: 60000,
  backoffMultiplier: 2,
};

export async function withRetry<T>(
  fn: () => Promise<T>,
  logger: Logger,
  config: Partial<RetryConfig> = {}
): Promise<{ result: T; attempts: number } | { error: Error; attempts: number }> {
  const { maxRetries, initialDelayMs, maxDelayMs, backoffMultiplier } = {
    ...DEFAULT_RETRY_CONFIG,
    ...config,
  };

  let lastError: Error | null = null;
  let delay = initialDelayMs;

  for (let attempt = 1; attempt <= maxRetries + 1; attempt++) {
    try {
      logger.info('retry.attempt', { retry_attempt: attempt, metadata: { max_retries: maxRetries } });

      const startTime = Date.now();
      const result = await fn();
      const duration = Date.now() - startTime;

      logger.info('retry.success', { retry_attempt: attempt, duration_ms: duration });
      return { result, attempts: attempt };
    } catch (error) {
      lastError = error instanceof Error ? error : new Error(String(error));

      logger.warn('retry.failed', {
        retry_attempt: attempt,
        error: { message: lastError.message },
        metadata: { will_retry: attempt <= maxRetries, next_delay_ms: delay },
      });

      if (attempt <= maxRetries) {
        await new Promise(resolve => setTimeout(resolve, delay));
        delay = Math.min(delay * backoffMultiplier, maxDelayMs);
      }
    }
  }

  logger.error('retry.exhausted', lastError!, { metadata: { total_attempts: maxRetries + 1 } });
  return { error: lastError!, attempts: maxRetries + 1 };
}

/**
 * Helper to extract output URL from various API response formats
 */
export function extractOutputUrl(result: Record<string, unknown>): string | null {
  // Check for direct output array with actual URLs (not empty)
  if (result.output && Array.isArray(result.output) && result.output.length > 0) {
    const firstOutput = result.output[0];
    if (typeof firstOutput === 'string' && firstOutput.startsWith('http')) {
      return firstOutput;
    }
  }

  // Check for direct output string
  if (result.output && typeof result.output === 'string' && (result.output as string).startsWith('http')) {
    return result.output as string;
  }

  // Check future_links (where completed videos will eventually be available)
  if (result.future_links && Array.isArray(result.future_links) && result.future_links.length > 0) {
    return result.future_links[0] as string;
  }

  return null;
}

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
import { Logger } from "./logger.ts";
import { executeGeminiImage } from "./providers/gemini-image.ts";
import { executeGeminiVision } from "./providers/gemini-vision.ts";
import { executeGrokVision } from "./providers/grok-vision.ts";
import { executeGrokText } from "./providers/grok-text.ts";
import { executeGrokVideo } from "./providers/grok-video.ts";
import {
  loadGenerationGlobals,
  applyVideoGlobals,
  isStepEnabled,
  getModelOverride,
  type GenerationGlobals,
} from "./generation-globals.ts";

// deno-lint-ignore no-explicit-any
type Json = Record<string, any>;

export interface PipelineContext {
  user_image: string;
  user_prompt: string;
  effect_id: string;
  effect_name: string;
  effect_concept: string;
  secondary_image?: string;
  /** Resolved target aspect ratio for all pipeline steps (e.g. "9:16", "16:9", "1:1") */
  target_aspect_ratio?: string;
  [key: string]: unknown;
}

export interface PipelineStep {
  id: string;
  pipeline_id: string;
  step_order: number;
  step_type: string;
  name: string;
  provider: string;
  config: Json;
  input_mapping: Json;
  output_mapping: Json;
  is_required: boolean;
  timeout_seconds: number;
  retry_config: Json;
  is_active: boolean;
}

export interface PipelineResult {
  pipelineExecutionId: string;
  providerRequestId?: string;
  finalPrompt?: string;
  finalImageUrl?: string;
  context: PipelineContext;
  grokVideoAttempts?: number;
}

/**
 * Resolve a dotted path from the pipeline context.
 * Supports: "pipeline.user_image", "steps.image_analyze.output.image_description"
 */
function resolveContextValue(context: PipelineContext, path: string): unknown {
  const parts = path.split(".");
  if (parts[0] === "pipeline") {
    return context[parts.slice(1).join(".")];
  }

  // deno-lint-ignore no-explicit-any
  let current: any = context;
  for (const part of parts) {
    if (current == null) return undefined;
    current = current[part];
  }
  return current;
}

/**
 * Resolve all input mappings for a step from the pipeline context.
 */
function resolveInputs(context: PipelineContext, inputMapping: Json): Json {
  const resolved: Json = {};
  if (!inputMapping) return resolved;
  let mapping = inputMapping;
  if (typeof mapping === "string") {
    try { mapping = JSON.parse(mapping); } catch (e) {}
  }
  for (const [key, path] of Object.entries(mapping)) {
    if (typeof path === "string") {
      resolved[key] = resolveContextValue(context, path);
      console.log(`[resolveInputs] key=${key}, path=${path}, resolved=${resolved[key]}`);
    } else {
      resolved[key] = path;
    }
  }
  return resolved;
}

/**
 * Store step outputs into the pipeline context via output_mapping.
 */
function storeOutputs(context: PipelineContext, stepName: string, outputMapping: Json, result: Json): void {
  // Store in the steps namespace
  if (!context.steps) {
    context.steps = {};
  }
  (context.steps as any)[stepName] = { output: result };

  if (!outputMapping) return;

  // Also map to specific context keys if requested
  for (const [contextKey, resultPath] of Object.entries(outputMapping)) {
    if (typeof resultPath === "string") {
      let path = resultPath;
      if (path.startsWith("result.")) {
        path = path.substring(7); // remove "result."
      }
      const parts = path.split(".");
      // deno-lint-ignore no-explicit-any
      let current: any = result;
      for (const part of parts) {
        if (current == null) break;
        current = current[part];
      }
      context[contextKey] = current;
    }
  }
}

/**
 * Substitute template variables like {{image_description}} from context.
 */
function substituteTemplate(template: string, context: PipelineContext): string {
  return template.replace(/\{\{(\w+)\}\}/g, (_match, key) => {
    const value = context[key];
    return value != null ? String(value) : "";
  });
}

/**
 * Execute a single pipeline step.
 */
async function executeStep(
  step: PipelineStep,
  context: PipelineContext,
  supabase: ReturnType<typeof createClient>,
  logger: Logger,
  pipelineExecutionId: string,
  globals: GenerationGlobals,
): Promise<{ result: Json; providerRequestId?: string }> {
  const inputs = resolveInputs(context, step.input_mapping);
  const config = step.config;
  const modelOverride = getModelOverride(globals, step.step_type);

  const promptTemplate = config.prompt_template as string | undefined;
  const resolvedPrompt = promptTemplate ? substituteTemplate(promptTemplate, context) : "";

  switch (step.step_type) {
    case "image_enhance": {
      const imageUrl = (inputs.image as string) || context.user_image;
      const output = await executeGeminiImage(
        {
          imageUrl,
          prompt: resolvedPrompt,
          model: modelOverride || (config.model as string | undefined),
          quality: config.quality as string | undefined,
          targetAspectRatio: (config.aspect_ratio as string) || (context.target_aspect_ratio as string) || undefined,
        },
        supabase,
        logger,
        pipelineExecutionId,
      );
      return {
        result: {
          image_url: output.imageUrl,
          storage_path: output.storagePath,
        },
      };
    }

    case "image_analyze": {
      const imageUrl = (inputs.image as string) || context.user_image;
      const outputKey = (config.output_key as string) || "image_description";

      if (step.provider === "gemini") {
        const output = await executeGeminiVision(
          {
            imageUrl,
            prompt: resolvedPrompt,
            model: modelOverride || (config.model as string | undefined),
            maxTokens: config.max_tokens as number | undefined,
          },
          logger,
        );
        return { result: { [outputKey]: output.description } };
      }

      const output = await executeGrokVision(
        {
          imageUrl,
          prompt: resolvedPrompt,
          model: modelOverride || (config.model as string | undefined),
          maxTokens: config.max_tokens as number | undefined,
        },
        logger,
      );
      return { result: { [outputKey]: output.description } };
    }

    case "prompt_enrich": {
      const output = await executeGrokText(
        {
          prompt: resolvedPrompt,
          model: modelOverride || (config.model as string | undefined),
          maxTokens: config.max_tokens as number | undefined,
        },
        logger,
      );
      const outputKey = (config.output_key as string) || "enriched_prompt";
      return { result: { [outputKey]: output.text } };
    }

    case "video_generate": {
      const promptSource = config.prompt_source as string | undefined;
      const imageSource = config.image_source as string | undefined;

      const finalPrompt = promptSource
        ? (context[promptSource] as string) || resolvedPrompt
        : resolvedPrompt || context.effect_concept;

      const finalImage = imageSource
        ? (context[imageSource] as string) || context.user_image
        : context.user_image;

      const rawAspectRatio = (context.target_aspect_ratio as string)
        || (config.aspect_ratio as string)
        || undefined;

      const videoParams = applyVideoGlobals(globals, {
        duration: config.duration as number | undefined,
        resolution: config.resolution as string | undefined,
        aspectRatio: rawAspectRatio,
        model: config.model as string | undefined,
      });

      const output = await executeGrokVideo(
        {
          imageUrl: finalImage,
          prompt: finalPrompt,
          model: videoParams.model,
          duration: videoParams.duration,
          aspectRatio: videoParams.aspectRatio,
          resolution: videoParams.resolution,
        },
        logger,
      );
      return {
        result: { request_id: output.requestId },
        providerRequestId: output.requestId,
      };
    }

    default:
      throw new Error(`Unknown step type: ${step.step_type}`);
  }
}

/**
 * Main pipeline orchestrator.
 * Loads steps, creates execution records, runs steps sequentially,
 * and returns the final result (including the video generation request_id).
 */
export async function runPipeline(
  pipelineId: string,
  generationId: string,
  context: PipelineContext,
  supabase: ReturnType<typeof createClient>,
  logger: Logger,
): Promise<PipelineResult> {
  logger.info("pipeline.start", { metadata: { pipeline_id: pipelineId, generation_id: generationId } });

  const globals = await loadGenerationGlobals(supabase, logger);

  const { data: steps, error: stepsError } = await supabase
    .from("pipeline_steps")
    .select("*")
    .eq("pipeline_id", pipelineId)
    .eq("is_active", true)
    .order("step_order", { ascending: true });

  if (stepsError || !steps?.length) {
    throw new Error(`Failed to load pipeline steps: ${stepsError?.message || "no steps found"}`);
  }

  logger.info("pipeline.steps_loaded", { metadata: { step_count: steps.length } });

  // Pre-flight: warn about input mappings that reference context keys not produced by earlier steps
  const producedKeys = new Set(["user_image", "user_prompt", "effect_id", "effect_name", "effect_concept", "secondary_image", "target_aspect_ratio", "effect_concept_resolved"]);
  for (const s of (steps as PipelineStep[])) {
    for (const [, path] of Object.entries(s.input_mapping)) {
      if (typeof path === "string" && path.startsWith("pipeline.")) {
        const key = path.substring(9);
        if (!producedKeys.has(key)) {
          logger.warn("pipeline.preflight.missing_input", {
            metadata: { step_name: s.name, step_order: s.step_order, missing_key: key },
          });
        }
      }
    }
    for (const [contextKey] of Object.entries(s.output_mapping)) {
      producedKeys.add(contextKey);
    }
  }

  const { data: pipelineExecution, error: peError } = await supabase
    .from("pipeline_executions")
    .insert({
      generation_id: generationId,
      pipeline_id: pipelineId,
      status: "running",
      current_step: 0,
      total_steps: steps.length,
      context,
      started_at: new Date().toISOString(),
    })
    .select()
    .single();

  if (peError) throw new Error(`Failed to create pipeline execution: ${peError.message}`);
  const pipelineExecutionId = pipelineExecution.id;

  await supabase
    .from("generations")
    .update({ pipeline_execution_id: pipelineExecutionId })
    .eq("id", generationId);

  let lastProviderRequestId: string | undefined;
  let grokVideoAttempts: number | undefined;

  for (let i = 0; i < steps.length; i++) {
    const step = steps[i] as PipelineStep;
    const stepStartTime = Date.now();

    if (!isStepEnabled(globals, step.step_type)) {
      logger.info("pipeline.step.skipped_by_globals", {
        metadata: { step_order: step.step_order, step_type: step.step_type, step_name: step.name },
      });

      await supabase
        .from("pipeline_step_executions")
        .insert({
          pipeline_execution_id: pipelineExecutionId,
          step_id: step.id,
          step_order: step.step_order,
          status: "skipped",
          input_data: {},
          output_data: { skipped_reason: "disabled_by_generation_globals" },
          started_at: new Date().toISOString(),
          completed_at: new Date().toISOString(),
          duration_ms: 0,
        });

      continue;
    }

    logger.info("pipeline.step.start", {
      metadata: { step_order: step.step_order, step_type: step.step_type, step_name: step.name },
    });

    const { data: stepExec } = await supabase
      .from("pipeline_step_executions")
      .insert({
        pipeline_execution_id: pipelineExecutionId,
        step_id: step.id,
        step_order: step.step_order,
        status: "running",
        input_data: resolveInputs(context, step.input_mapping),
        started_at: new Date().toISOString(),
      })
      .select()
      .single();

    await supabase
      .from("pipeline_executions")
      .update({ current_step: i + 1 })
      .eq("id", pipelineExecutionId);

    try {
      const { result, providerRequestId } = await executeStep(
        step,
        context,
        supabase,
        logger,
        pipelineExecutionId,
        globals,
      );

      storeOutputs(context, step.name, step.output_mapping, result);

      if (providerRequestId) {
        lastProviderRequestId = providerRequestId;
      }

      const durationMs = Date.now() - stepStartTime;

      if (stepExec) {
        await supabase
          .from("pipeline_step_executions")
          .update({
            status: "completed",
            output_data: result,
            provider_request_id: providerRequestId || null,
            completed_at: new Date().toISOString(),
            duration_ms: durationMs,
          })
          .eq("id", stepExec.id);
      }

      logger.info("pipeline.step.completed", {
        metadata: { step_order: step.step_order, step_type: step.step_type, duration_ms: durationMs },
      });
    } catch (error) {
      const durationMs = Date.now() - stepStartTime;
      const errMsg = error instanceof Error ? error.message : String(error);

      if (stepExec) {
        await supabase
          .from("pipeline_step_executions")
          .update({
            status: "failed",
            error_message: errMsg,
            completed_at: new Date().toISOString(),
            duration_ms: durationMs,
          })
          .eq("id", stepExec.id);
      }

      logger.error("pipeline.step.failed", error instanceof Error ? error : new Error(errMsg));

      if (step.is_required) {
        await supabase
          .from("pipeline_executions")
          .update({
            status: "failed",
            error_message: `Step "${step.name}" failed: ${errMsg}`,
            completed_at: new Date().toISOString(),
          })
          .eq("id", pipelineExecutionId);

        throw new Error(`Pipeline step "${step.name}" failed: ${errMsg}`);
      }

      if (stepExec) {
        await supabase
          .from("pipeline_step_executions")
          .update({ status: "skipped" })
          .eq("id", stepExec.id);
      }
    }
  }

  const finalStatus = lastProviderRequestId ? "running" : "completed";
  await supabase
    .from("pipeline_executions")
    .update({
      status: finalStatus,
      context,
      step_results: steps.map((s: PipelineStep) => ({
        step_id: s.id,
        step_type: s.step_type,
        name: s.name,
      })),
      ...(finalStatus === "completed" ? { completed_at: new Date().toISOString() } : {}),
    })
    .eq("id", pipelineExecutionId);

  logger.info("pipeline.orchestration_done", {
    metadata: {
      pipeline_execution_id: pipelineExecutionId,
      status: finalStatus,
      has_video_request: !!lastProviderRequestId,
    },
  });

  return {
    pipelineExecutionId,
    providerRequestId: lastProviderRequestId,
    finalPrompt: (context.video_prompt as string) || (context.enriched_prompt as string) || (context.effect_concept as string),
    finalImageUrl: (context.enhanced_image as string) || context.user_image,
    context,
    grokVideoAttempts,
  };
}

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
import { Logger } from "../logger.ts";

export interface GeminiImageInput {
  imageUrl: string;
  prompt: string;
  model?: string;
  quality?: string;
  /** Target output aspect ratio (e.g. "9:16", "16:9"). Supported by gemini-3.1-flash-image-preview. */
  targetAspectRatio?: string;
}

export interface GeminiImageOutput {
  imageUrl: string;
  storagePath: string;
}

async function fetchImageAsBase64(url: string): Promise<{ base64: string; mimeType: string }> {
  const res = await fetch(url);
  if (!res.ok) throw new Error(`Failed to fetch image: HTTP ${res.status}`);
  const buffer = await res.arrayBuffer();
  const bytes = new Uint8Array(buffer);
  const mimeType = res.headers.get("content-type") || "image/jpeg";

  let binary = "";
  for (let i = 0; i < bytes.length; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return { base64: btoa(binary), mimeType };
}

export async function executeGeminiImage(
  input: GeminiImageInput,
  supabase: ReturnType<typeof createClient>,
  logger: Logger,
  executionId: string,
): Promise<GeminiImageOutput> {
  const apiKey = Deno.env.get("GEMINI_API_KEY");
  if (!apiKey) throw new Error("GEMINI_API_KEY not configured");

  const model = input.model || "gemini-3.1-flash-image-preview";
  logger.info("gemini.image.start", {
    metadata: { model, prompt_length: input.prompt.length, target_aspect_ratio: input.targetAspectRatio },
  });

  const { base64, mimeType } = await fetchImageAsBase64(input.imageUrl);
  logger.info("gemini.image.fetched_source", { metadata: { mime: mimeType } });

  const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${apiKey}`;

  // deno-lint-ignore no-explicit-any
  const generationConfig: Record<string, any> = {
    responseModalities: ["IMAGE", "TEXT"],
    temperature: 0.4,
  };

  generationConfig.imageConfig = {
    imageSize: "2K",
  };

  if (input.targetAspectRatio) {
    generationConfig.imageConfig.aspectRatio = input.targetAspectRatio;
  }

  const body = {
    contents: [
      {
        parts: [
          { text: input.prompt },
          { inline_data: { mime_type: mimeType, data: base64 } },
        ],
      },
    ],
    generationConfig,
  };

  const res = await fetch(apiUrl, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });

  if (!res.ok) {
    const errText = await res.text();
    // Fallback for region restrictions
    if (res.status === 400 && errText.includes("not available in your country")) {
      logger.warn("gemini.image.region_blocked", { metadata: { error: errText } });
      return { imageUrl: input.imageUrl, storagePath: "" };
    }
    throw new Error(`Gemini API ${res.status}: ${errText}`);
  }

  const data = await res.json();
  logger.info("gemini.image.response_received");

  const candidates = data.candidates;
  if (!candidates?.length) throw new Error("Gemini returned no candidates");

  let resultBase64: string | null = null;
  let resultMime = "image/png";

  for (const part of candidates[0].content?.parts || []) {
    const inlineData = part.inlineData || part.inline_data;
    if (inlineData) {
      resultBase64 = inlineData.data;
      resultMime = inlineData.mimeType || inlineData.mime_type || "image/png";
      break;
    }
  }

  if (!resultBase64) {
    logger.warn("gemini.image.no_image_data", { metadata: { message: "Gemini response contained no image data, falling back to original image" } });
    return { imageUrl: input.imageUrl, storagePath: "" };
  }

  const ext = resultMime.includes("png") ? "png" : "jpg";
  const storagePath = `pipeline/${executionId}/enhanced.${ext}`;

  let binary = "";
  const decoded = atob(resultBase64);
  for (let i = 0; i < decoded.length; i++) {
    binary += String.fromCharCode(decoded.charCodeAt(i));
  }
  const imageBytes = new Uint8Array(decoded.length);
  for (let i = 0; i < decoded.length; i++) {
    imageBytes[i] = decoded.charCodeAt(i);
  }

  const { error: uploadErr } = await supabase.storage
    .from("pipeline-artifacts")
    .upload(storagePath, imageBytes, { contentType: resultMime, upsert: true });

  if (uploadErr) throw new Error(`Storage upload failed: ${uploadErr.message}`);

  const { data: publicUrlData } = supabase.storage
    .from("pipeline-artifacts")
    .getPublicUrl(storagePath);

  const imageUrl = publicUrlData.publicUrl;
  logger.info("gemini.image.completed", { metadata: { storage_path: storagePath, url: imageUrl } });

  return { imageUrl, storagePath };
}

